def check_parity(a, b, c):
    return a == b == c

print(check_parity({"x": 1}, {"x": 1}, {"x": 1}), "|", check_parity({"x": 1}, {"x": 1}, {"x": 2}))

def fmt_pen(x):
    return f"{round(float(x), 1)} PEN"

print(fmt_pen(28.04))

def a11y_min(has_h1, alts):
    return has_h1 and all(len(a) > 10 for a in alts)

print(a11y_min(True, ["descripcion larga de figura"]), "|", a11y_min(True, ["corto"]))

def ready(checklist):
    return all(checklist.values())

print(ready({"dashboard": True, "xlsx": True, "doc": True}), "|", ready({"dashboard": True, "xlsx": False, "doc": True}))
